@charset "UTF-8";
body {
  margin: 0;
  padding-top: 20px;
  padding-bottom: 20px;
}

.bill-header-container {
  font-family: system-ui, sans-serif;
  background: #f4f5f7;
  border-radius: 6px;
  padding: 6px 10px;
  box-sizing: border-box;
  font-size: 13px;
  color: #222;
  position: relative;
}

.bill-header-top {
  display: flex;
  align-items: flex-start;
  flex-wrap: nowrap;
}

.triangle {
  color: #001f52;
  font-size: 25px;
  cursor: pointer;
  user-select: none;
  flex-shrink: 0;
  margin-top: -7px;
  margin-right: 8px;
}

.bill-header-content {
  flex: 1;
  display: flex;
  flex-wrap: wrap;
  align-items: center;
}

.bill-header-row {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 25px;
  row-gap: 12px;
}

.bill-label {
  display: flex;
  align-items: center;
  gap: 4px;
  color: #444;
  white-space: nowrap;
}

.bill-label b {
  color: #000;
  font-weight: 600;
}

.truncate {
  display: inline-block;
  max-width: 220px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  vertical-align: bottom;
}

.copy-icon {
  cursor: pointer;
  color: #777;
  transition: color 0.2s ease, transform 0.1s ease;
}

.copy-icon:hover {
  color: #000;
  transform: scale(1.1);
}

.no-data {
  text-align: center;
  color: #777;
  font-size: 14px;
  padding: 10px;
}

/* ✅ Toast notification */
.copy-toast-top {
  font-family: system-ui, sans-serif;
  position: fixed;
  top: 20px;
  left: 50%;
  transform: translateX(-50%);
  background: #e8f4cf;
  color: #2e3b00;
  padding: 8px 14px;
  border-radius: 6px;
  font-size: 13px;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
  display: flex;
  align-items: center;
  gap: 8px;
  z-index: 9999;
  animation: slideDown 0.3s ease forwards, fadeOut 2s ease 1s forwards;
}

.toast-close {
  cursor: pointer;
  color: #333;
  transition: opacity 0.2s;
}

.toast-close:hover {
  opacity: 0.6;
}

@keyframes slideDown {
  from {
    transform: translate(-50%, -20px);
    opacity: 0;
  }
  to {
    transform: translate(-50%, 0);
    opacity: 1;
  }
}
@keyframes fadeOut {
  0% {
    opacity: 1;
  }
  90% {
    opacity: 1;
  }
  100% {
    opacity: 0;
  }
}
/* Tooltip styles */
.tooltip-container {
  position: relative;
  cursor: default;
}

.tooltip-text {
  visibility: hidden;
  opacity: 0;
  width: max-content;
  max-width: 260px;
  background-color: #fff;
  color: #000;
  text-align: center;
  border-radius: 6px;
  padding: 6px 10px;
  position: absolute;
  z-index: 10;
  bottom: 125%; /* position above the text */
  left: 50%;
  transform: translateX(-50%) translateY(6px);
  font-size: 12px;
  white-space: nowrap;
  transition: opacity 0.25s ease, transform 0.25s ease;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
}

/* Tooltip arrow */
.tooltip-text::after {
  content: "";
  position: absolute;
  top: 100%;
  left: 50%;
  margin-left: -5px;
  border-width: 5px;
  border-style: solid;
  border-color: #001f52 transparent transparent transparent;
}

/* Hover state */
.tooltip-container:hover .tooltip-text {
  visibility: visible;
  opacity: 1;
  transform: translateX(-50%) translateY(0);
}

.bill-summary-bar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  background: #e6f0ff; /* light blue background */
  border-radius: 6px;
  padding: 10px 18px;
  margin-bottom: 10px;
  font-family: system-ui, sans-serif;
  font-size: 14px;
  color: #001f52;
  font-weight: 500;
  box-sizing: border-box;
}

.bill-summary-item {
  display: flex;
  gap: 10px;
}

.bill-summary-label {
  color: #333;
  font-size: 13px;
}

.bill-summary-value {
  color: #001f52;
  font-weight: 600;
}

.bill-summary-value.total {
  color: #000d33;
  font-weight: 700;
}

