              </span>

              {/* Vendor Name */}
              <Tooltip text={tooltipText("Vendor Name", vendor_name)}>
                <span className="bill-label truncate">
                  Vendor Name <b>{vendor_name || " "}</b>
                </span>
              </Tooltip>

              {/* Vendor ID */}
              <Tooltip
                text={tooltipText(
                  "Vendor ID",
                  `${vendor_id || ""}${
                    provider_vendor_id
                      ? ` (Provider Vendor ${provider_vendor_id})`
                      : ""
                  }`
                )}
              >
                <span className="bill-label truncate">
                  Vendor ID{" "}
                  <b>
                    {vendor_id || " "}
                    {provider_vendor_id
                      ? ` (Provider Vendor ${provider_vendor_id})`
                      : ""}
                  </b>
                </span>
              </Tooltip>

              {/* Invoice Date */}
              <span className="bill-label">
                Invoice Date <b>{invoice_date || " "}</b>
              </span>

              {expanded && (
                <>
                  {/* Utilities */}
                  <Tooltip
                    text={
                      utility_list?.length > 0
                        ? utility_list.join(", ")
                        : "N/A"
                    }
                  >
                    <span className="bill-label">
                      Utilities{" "}
                      <b>
                        {utility_list?.length > 0
                          ? utility_list.map((ut, index) => {
                              const iconName =
                                utilityIcons[ut.toUpperCase()] || "Package";
                              const Icon = LucideIcons[iconName];
                              return (
                                <span
                                  key={index}
                                  style={{
                                    display: "inline-flex",
                                    alignItems: "center",
                                    marginRight: "6px",
                                  }}
                                >
                                  {Icon && (
                                    <Icon
                                      size={16}
                                      strokeWidth={2}
                                      style={{
                                        marginRight: "4px",
                                        verticalAlign: "middle",
                                      }}
                                    />
                                  )}
                                  {ut}
                                  {index < utility_list.length - 1 && ","}
                                </span>
                              );
                            })
                          : "N/A"}
                      </b>
                    </span>
                  </Tooltip>

                  {/* Total Accounts */}
                  <span className="bill-label">
                    Total Accounts <b>{totalAccounts || 0}</b>
                  </span>

                  {/* Vendor Main Phone */}
                  <span className="bill-label">
                    Vendor Main Phone <b>{main_phone || "N/A"}</b>
                  </span>
                </>
              )}
            </div>
          </div>
        </div>
      </div>
    </>
  );
}

// ---------------- Main App ----------------
function App() {
  const [data, setData] = useState(null);
  const [totalAccounts, setTotalAccounts] = useState(0);
  const [lastUpdate, setLastUpdate] = useState(null);

  const updateFromModel = () => {
    const model = appsmith?.model || {};
    const dataArr = model?.data || [];

    if (Array.isArray(dataArr) && dataArr.length > 0) {
      const billData = dataArr[0];
      const utilityTypes = [...new Set(dataArr.map((item) => item.utility_type))];
      billData.utility_list = utilityTypes;

      setData(billData);
      setTotalAccounts(model.total_accounts || 0);
      setLastUpdate(Date.now());
    } else {
      setData(null);
      setTotalAccounts(0);
    }
  };

  useEffect(() => {
    updateFromModel();

    // ✅ Poll every 1 second to detect query re-runs
    const interval = setInterval(() => {
      const model = appsmith?.model || {};
      const dataArr = model?.data || [];
      if (JSON.stringify(dataArr) !== JSON.stringify(data)) {
        updateFromModel();
      }
    }, 1000);

    return () => clearInterval(interval);
  }, []);

  if (!data) return <div className="no-data">Data is Loading...</div>;

  return <BillHeader data={data} totalAccounts={totalAccounts} />;
}

// ---------------- Render ----------------
appsmith.onReady(() => {
  ReactDOM.render(<App />, document.getElementById("root"));
});
